import dspy

class HallucinationChecker(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate_fact = dspy.ChainOfThought('fact -> answer')

    def forward(self, fact):
        pred = self.generate_fact(fact=fact)
        # Detect hallucination via length/entropy
        answer_len = len(pred.answer.strip())
        if answer_len < 10 or answer_len > 200:
            raise ValueError(f'Hallucination detected: abnormal answer length {answer_len}')
        return pred

import dspy
from typing import Dict, Any

def monitor_assertions(module: dspy.Module, example: dspy.Example) -> Dict[str, Any]:
    try:
        prediction = module.forward(**example.inputs())
        # Check basic factual assertions
        assert 'I don't know' not in prediction.answer, 'Uncertainty hallucination'
        assert len(prediction.answer.split()) > 5, 'Too brief - likely hallucination'
        return {'status': 'PASS', 'prediction': prediction}
    except AssertionError as e:
        return {'status': 'HALLUCINATION', 'error': str(e), 'example': example}

import re
import dspy

def validate_cot_logic(prediction: dspy.Prediction) -> bool:
    if hasattr(prediction, 'reasoning'):
        reasoning = prediction.reasoning
        # Detect common hallucination patterns
        hallucination_patterns = [
            r'\b(approximately|roughly|about)\s+\d+',  # Vague quantification
            r'\b(I think|probably|maybe)\b',           # Uncertainty
            r'\b(first|second|third).*?(but|however)', # Contradictory logic
        ]
        for pattern in hallucination_patterns:
            if re.search(pattern, reasoning, re.IGNORECASE):
                return False
    return True

