class HallucinationResistantAgent(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate = dspy.ChainOfThought('question -> answer')
        self.verify = dspy.ChainOfThought('claim, evidence -> verified:bool, explanation')

    def forward(self, question):
        # Generate initial answer
        pred = self.generate(question=question)

        # Self-verify
        verification = self.verify(
            claim=pred.answer,
            evidence=question
        )

        if verification.verified.lower() == 'false':
            pred.answer = 'Insufficient information to answer confidently.'

        return pred

